const senderName = [message?.from?.first_name, message?.from?.last_name].filter(Boolean).join(" ") || message?.from?.username || "Unknown";
const isFromOwner = Boolean(ownerUserId && fromId === ownerUserId);
const sessionKey = businessConnectionId && chatId ? `${businessConnectionId}:${chatId}` : chatId ? `chat:${chatId}` : `update:${update.update_id}`;
return {
  json: {
    updateId: update.update_id,
    updateType: update.business_message ? "business_message" : update.message ? "message" : "other",
    businessConnectionId,
    chatId,
    fromId,
    ownerUserId,
    isFromOwner,
    messageId: message?.message_id ?? null,
    senderName,
    username: message?.from?.username ?? null,
    userText,
    sessionKey,
    shouldReply: Boolean(businessConnectionId && chatId && trimmedText && !isFromOwner),
    shouldUpdateMemory: Boolean(businessConnectionId && chatId && trimmedText),
